#include <stdio.h>
#include <string.h>

#define N 100005
#define M 100005

int dp[N][M], n, m, q, i, j, k, l;
char s[N], p[M];

int main() {
    scanf("%d", &q);
    while (q--) {
        scanf("%s", p);
        l = strlen(p);
        for (i = 0; i <= n; i++) {
            for (j = 0; j <= m; j++) {
                dp[i][j] = 0;
            }
        }
        for (i = 0; i <= n; i++) {
            for (j = 0; j <= m; j++) {
                if (i > 0) {
                    dp[i][j] += dp[i - 1][j];
                }
                if (j > 0) {
                    dp[i][j] += dp[i][j - 1];
                }
                if (i > 0 && j > 0) {
                    dp[i][j] -= dp[i - 1][j - 1];
                }
                if (i > 0 && j > 0 && s[i - 1] == p[j - 1]) {
                    dp[i][j]++;
                }
            }
        }
        n += l;
        for (i = 0; i <= m; i++) {
            dp[n][i] += dp[n - 1][i];
            if (i > 0) {
                dp[n][i] += dp[n][i - 1];
            }
            if (i > 0 && s[n - 1 - i] == p[i - 1]) {
                dp[n][i]++;
            }
        }
        printf("%d\n", dp[n][m]);
    }
    return 0;
}

